prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?cycleStart ?cycleNode ?cyclePathLen ?cycleNodeName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?cycleStart tai:belongsTo ?choreo ; bbo:name ?sName .
  FILTER(BOUND(?sName))

  {
    SELECT DISTINCT ?cycleStart ?cycleNode (COUNT(?mid) AS ?cyclePathLen) WHERE {
      ?cycleStart ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?cycleNode .
      FILTER(?cycleNode = ?cycleStart)

      OPTIONAL {
        SELECT ?cycleStart ?cycleNode ?mid WHERE {
          ?cycleStart ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?cycleNode .
          FILTER(?cycleNode = ?cycleStart)
          BIND(0 AS ?mid)
        }
      }
    }
    GROUP BY ?cycleStart ?cycleNode
  }

  OPTIONAL { ?cycleNode bbo:name ?cycleNodeName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?nodeA ?nodeB ?nameA ?nameB WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5a8e825c3a9a4049b67ab53c2ba7abc8" ;
         tai:belongsTo ?org .
  ?org tai:belongsTo ?corpus .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?nodeA tai:belongsTo ?choreo ; bbo:name ?nameA .
  OPTIONAL { ?nodeA bbo:id ?idA . }

  {
    ?edge a bbo:SequenceFlow ;
          tai:belongsTo ?choreo ;
          bbo:has_sourceRef ?nodeA ;
          bbo:has_targetRef ?nodeB .
  }

  OPTIONAL { ?nodeB bbo:name ?nameB . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelId ?modelNorm ?modelOrig ?choreo ?edge ?src ?tgt WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelNorm ;
         tai:originalId ?modelOrig .

  FILTER(?modelNorm = "5a8e825c3a9a4049b67ab53c2ba7abc8" || ?modelOrig = "5a8e825c3a9a4049b67ab53c2ba7abc8").

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?edge a bbo:SequenceFlow ;
        tai:belongsTo ?choreo ;
        bbo:has_sourceRef ?src ;
        bbo:has_targetRef ?tgt .

  OPTIONAL { ?model bbo:name ?modelId . }
}
LIMIT 25
